select.if:
select curCom.id, curCom.code, curCom.full_name as fullName, curCom.short_name as shortName, curCom.description, curCom.full_path as fullPath, curCom.lay_no as layNo, curCom.sort, curCom.valid, curCom.modify_time as modifyTime, parentCom.code as parentCode from org_company curCom left join org_company parentCom on curCom.parent_id = parentCom.id
where curCom.modify_time > #{modifyTime}
where curCom.valid =1
order by curCom.lay_no, curCom.sort
limit #{pageSize} offset #{offset}

select count(*) from org_company curCom left join org_company parentCom on curCom.parent_id = parentCom.id

    where curCom.modify_time > #{modifyTime}


    where curCom.valid =1

mapper.select:
select curCom.id, curCom.code, curCom.full_name as fullName, curCom.short_name as shortName, curCom.description, curCom.full_path as fullPath, curCom.lay_no as layNo, curCom.sort,
curCom.valid, curCom.modify_time as modifyTime, parentCom.code as parentCode
from org_company curCom left join org_company parentCom on curCom.parent_id = parentCom.id where curCom.valid =1 and curCom.code =#{companyCode}

select.if:
select curCom.id, curCom.code, curCom.full_name as fullName, curCom.short_name as shortName, curCom.description, curCom.full_path as fullPath, curCom.lay_no as layNo, curCom.sort, curCom.valid, curCom.modify_time as modifyTime, parentCom.code as parentCode from org_company curCom left join org_company parentCom on curCom.parent_id = parentCom.id where curCom.full_path LIKE #{fullPath} and curCom.valid =1
and curCom.short_name like #{keyword}
and curCom.lay_no = #{layNo} + 1
order by curCom.lay_no, curCom.sort limit #{pageSize} offset #{mysqlOffset}

mapper.select:
select count(1) from org_company curCom left join org_company parentCom on curCom.parent_id = parentCom.id where curCom.full_path LIKE #{fullPath} and curCom.valid =1
and curCom.short_name like #{keyword}
and curCom.lay_no = #{layNo} + 1
